import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: String {
        switch self {
        case .development:
            return "https://dev.api.example.com"
        case .staging:
            return "https://staging.api.example.com"
        case .production:
            return "https://api.example.com"
        }
    }
}

class APIClient {
    private let session: URLSession
    private let environment: Environment
    
    init(environment: Environment = .development) {
        self.session = URLSession.shared
        self.environment = environment
    }
    
    func fetchData(completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(environment.baseURL)/data")!
        
        session.dataTask(with: url) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "NoData", code: -1, userInfo: nil)))
                return
            }
            
            completion(.success(data))
        }.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<Bool, Error>) -> Void) {
        let url = URL(string: "\(environment.baseURL)/auth")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        
        let authData = ["username": username, "password": password]
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: authData, options: [])
            request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        } catch {
            completion(.failure(error))
            return
        }
        
        session.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "NoHTTPResponse", code: -1, userInfo: nil)))
                return
            }
            
            let isSuccess = (200...299).contains(httpResponse.statusCode)
            completion(.success(isSuccess))
        }.resume()
    }
}